import{_ as r,o as l,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"01-4 LNG / LPG 船產業結構","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-4_LNG_LPG船.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-4_LNG_LPG船.md"}'),o={name:"Deep32Q知識庫/產業洞察/航運產業/01_次產業結構/01-4_LNG_LPG船.md"};function n(i,t,s,g,d,h){return l(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_01-4-lng-lpg-船產業結構" tabindex="-1">01-4 LNG / LPG 船產業結構 <a class="header-anchor" href="#_01-4-lng-lpg-船產業結構" aria-label="Permalink to &quot;01-4 LNG / LPG 船產業結構&quot;">​</a></h1><h2 id="一、lng-船-液化天然氣運輸船" tabindex="-1">一、LNG 船（液化天然氣運輸船） <a class="header-anchor" href="#一、lng-船-液化天然氣運輸船" aria-label="Permalink to &quot;一、LNG 船（液化天然氣運輸船）&quot;">​</a></h2><h3 id="市場規模" tabindex="-1">市場規模 <a class="header-anchor" href="#市場規模" aria-label="Permalink to &quot;市場規模&quot;">​</a></h3><ul><li><strong>2025 年</strong>：約 154.7～163 億美元</li><li><strong>2026 年</strong>：約 166.2～174 億美元</li><li><strong>CAGR（2026-2031）</strong>：約 5.7%～6.9%</li></ul><h3 id="全球液化天然氣貿易趨勢" tabindex="-1">全球液化天然氣貿易趨勢 <a class="header-anchor" href="#全球液化天然氣貿易趨勢" aria-label="Permalink to &quot;全球液化天然氣貿易趨勢&quot;">​</a></h3><ul><li><strong>2025 年全球 LNG 供應</strong>：約 429 百萬噸</li><li><strong>2026 年預估</strong>：472 百萬噸（年增約 7%）</li><li><strong>新增液化產能</strong>：2026 年預計增加約 43 mtpa（百萬噸/年） <ul><li>卡塔爾 North Field Expansion：16.5 mtpa</li><li>美國 Golden Pass T1：6 mtpa</li><li>Corpus Christi Phase-3 / Block2-7：8.6 mtpa</li></ul></li><li><strong>美國產能</strong>：2025 年 1.1 億噸 → 2026 年 1.3 億噸</li><li><strong>需求端</strong>：歐洲冬季儲氣低於 30%、中國進口預估年增 11%（達 7,560 萬噸）、印度需求增 5 百萬噸</li></ul><h3 id="船隊與訂單" tabindex="-1">船隊與訂單 <a class="header-anchor" href="#船隊與訂單" aria-label="Permalink to &quot;船隊與訂單&quot;">​</a></h3><ul><li><strong>現有船隊</strong>：約 700+ 艘 LNG 運輸船</li><li><strong>2025 年交船</strong>：76 艘（含 25% 延誤率）</li><li><strong>2026 年計畫交船</strong>：約 100 艘（含 85 艘 LNGC）</li><li><strong>訂單簿</strong>：334 艘（含 282 艘 LNGC），訂單/船隊比約 40%（部分來源指超過 45-50%）</li><li><strong>報廢</strong>：2025 年創紀錄報廢 15 艘 LNGC，2026 年更多老舊蒸汽船可能退出租約</li></ul><h3 id="運價展望" tabindex="-1">運價展望 <a class="header-anchor" href="#運價展望" aria-label="Permalink to &quot;運價展望&quot;">​</a></h3><ul><li><strong>2025 年</strong>：創多年度低點</li><li><strong>2026 年展望</strong>：船隊擴張速度快於液化產能建設，運價承壓；但冬季需求與亞洲進口增長提供支撐</li></ul><h2 id="二、lpg-船-液化石油氣運輸船" tabindex="-1">二、LPG 船（液化石油氣運輸船） <a class="header-anchor" href="#二、lpg-船-液化石油氣運輸船" aria-label="Permalink to &quot;二、LPG 船（液化石油氣運輸船）&quot;">​</a></h2><h3 id="市場規模-1" tabindex="-1">市場規模 <a class="header-anchor" href="#市場規模-1" aria-label="Permalink to &quot;市場規模&quot;">​</a></h3><ul><li><strong>2025 年</strong>：約 2,306 億美元（含 LPG 商品本身）</li><li><strong>2026 年</strong>：約 2,433 億美元</li><li><strong>CAGR（2026-2031）</strong>：約 5.2%</li></ul><h3 id="全球-lpg-貿易趨勢" tabindex="-1">全球 LPG 貿易趨勢 <a class="header-anchor" href="#全球-lpg-貿易趨勢" aria-label="Permalink to &quot;全球 LPG 貿易趨勢&quot;">​</a></h3><ul><li><strong>2026 年貿易增長</strong>：預估約 6%</li><li><strong>主要出口國</strong>：美國（页岩氣副產乙烷/丙烷）、中東（沙烏地阿拉伯 Jafurah 氣田擴產）</li><li><strong>主要進口國</strong>：中國、印度（新進口終端建設推動需求）</li></ul><h3 id="船型分類" tabindex="-1">船型分類 <a class="header-anchor" href="#船型分類" aria-label="Permalink to &quot;船型分類&quot;">​</a></h3><ul><li><strong>VLGC</strong>（Very Large Gas Carrier，超大型氣體運輸船）：2025 年佔 LPG 船隊約 35.5%，CAGR 約 5.7%</li><li><strong>VLAC</strong>（Very Large Ethane Carrier，超大型乙烷運輸船）：專注美國乙烷出口</li><li><strong>LPG 雙燃料船</strong>：膜式儲槽技術與雙燃料改造提升載運量與能源效率</li></ul><h3 id="船隊與訂單-1" tabindex="-1">船隊與訂單 <a class="header-anchor" href="#船隊與訂單-1" aria-label="Permalink to &quot;船隊與訂單&quot;">​</a></h3><ul><li><strong>2025 年交船</strong>：98 艘（含 21 艘 VLGC、10 艘 VLAC）</li><li><strong>全球 LPG 船隊擴張</strong>：2026 年預估增加約 180 艘</li><li><strong>訂單/船隊比</strong>：交船高峰在 2027 年（達 16% 的年增長率）</li></ul><h3 id="運價展望-1" tabindex="-1">運價展望 <a class="header-anchor" href="#運價展望-1" aria-label="Permalink to &quot;運價展望&quot;">​</a></h3><ul><li><strong>2026 年 VLGC 期租運價</strong>：預估下跌約 5%，平均日租金約 $40,000</li><li><strong>關鍵壓力</strong>：船隊擴張速度快於需求增長，尤其 2027 年交船高峰可能加劇供過於求</li><li><strong>支撐因素</strong>：美國出口終端擴建、亞洲進口需求增長、紅海繞航增加噸海里</li></ul><h2 id="三、lng-與-lpg-的關鍵差異" tabindex="-1">三、LNG 與 LPG 的關鍵差異 <a class="header-anchor" href="#三、lng-與-lpg-的關鍵差異" aria-label="Permalink to &quot;三、LNG 與 LPG 的關鍵差異&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">項目</th><th>LNG 船</th><th>LPG 船</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>運送物質</strong></td><td>液化天然氣（甲烷，-162°C）</td><td>液化石油氣（丙烷/丁烷，約 -42°C～+0°C）</td></tr><tr><td style="text-align:center;"><strong>儲槽技術</strong></td><td>Membrane（GTT NO96/Mark III）、MOSS 球型</td><td>壓力式、半壓半冷、全冷式膜儲槽</td></tr><tr><td style="text-align:center;"><strong>典型載量</strong>：約 140,000～175,000 m³</td><td>約 80,000～140,000 m³（VLGC）</td><td></td></tr><tr><td style="text-align:center;"><strong>主要貿易流向</strong>：中東/美國 → 亞洲、歐洲</td><td>美國/中東 → 亞洲</td><td></td></tr><tr><td style="text-align:center;"><strong>訂單/船隊比</strong>：約 40-50%</td><td>約 30-40%（交船高峰在 2027）</td><td></td></tr></tbody></table><blockquote><p>資料來源：Mordor Intelligence（LNG/LPG 市場報告）、Research Nester、Drewry Maritime Research、ICIS Global LNG Outlook 2026、Kpler、Fortune Business Insights、Drewry LPG Shipping 2026 展望</p></blockquote>',24)])])}const G=r(o,[["render",n]]);export{c as __pageData,G as default};
